const rows = $input.all();
const runSource = 'cron';
const sourceSheet = 'Weekly Data';
const ingredientColumns = ['Flour (kg)', 'Cheese (kg)', 'Tomato Sauce (kg)', 'Beef (kg)', 'Pasta (kg)'];
const stockKeys = ['stock_kg', 'Stock (kg)', 'Current Stock', 'current_stock', 'current_kg', 'stock', 'Stock'];
const itemKeys = ['item_name', 'Item', 'item', 'Ingredient', 'ingredient', 'Name', 'name'];

function firstValue(row, keys) {
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && String(row[key]).trim() !== '') return row[key];
  }
  return undefined;
}

function parseStock(value) {
  if (value === undefined || value === null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
  const cleaned = String(value).replace(/,/g, '').replace(/kg/gi, '').trim();
  if (cleaned === '') return null;
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
}

function sourceRow(row, index) {
  return row.row_number || row.Row || row.row || row.__rowNumber || index + 2;
}

function hasWideInventoryShape(row) {
  return ingredientColumns.some((columnName) => Object.prototype.hasOwnProperty.call(row, columnName));
}

const inventoryItems = [];
const invalidRows = [];
const indexedRows = rows.map((item, index) => ({ item, index }));
const hasDirectItemRows = indexedRows.some(({ item }) => firstValue(item.json, itemKeys) !== undefined);
const rowsToProcess = hasDirectItemRows
  ? indexedRows
  : indexedRows.filter(({ item }) => hasWideInventoryShape(item.json)).slice(-1);

rowsToProcess.forEach(({ item, index }) => {
  const row = item.json;
  const rowNumber = sourceRow(row, index);
  const lastUpdated = row.last_updated || row.LastUpdated || row.Date || row.date || new Date().toISOString();
  const directItemName = firstValue(row, itemKeys);
  const directStock = parseStock(firstValue(row, stockKeys));

  if (directItemName !== undefined) {
    if (directStock === null) {
      invalidRows.push({ source_row: rowNumber, item_name: String(directItemName), reason: 'Missing or non-numeric stock_kg' });
    } else {
      inventoryItems.push({ item_name: String(directItemName), stock_kg: directStock, last_updated: lastUpdated, source_row: rowNumber });
    }
    return;
  }

  let foundWideStock = false;
  for (const columnName of ingredientColumns) {
    if (!Object.prototype.hasOwnProperty.call(row, columnName)) continue;
    foundWideStock = true;
    const stockKg = parseStock(row[columnName]);
    const itemName = columnName.replace(/\s*\(kg\)$/i, '');
    if (stockKg === null) {
      invalidRows.push({ source_row: rowNumber, item_name: itemName, field: columnName, reason: 'Missing or non-numeric stock_kg' });
    } else {
      inventoryItems.push({ item_name: itemName, stock_kg: stockKg, last_updated: lastUpdated, source_row: rowNumber });
    }
  }

  if (!foundWideStock && Object.keys(row).length > 0) {
    invalidRows.push({ source_row: rowNumber, reason: 'No supported inventory columns found' });
  }
});

return [{
  json: {
    run_source: runSource,
    checked_at: new Date().toISOString(),
    source_sheet: sourceSheet,
    item_count: inventoryItems.length,
    invalid_count: invalidRows.length,
    inventory_items: inventoryItems,
    invalid_rows: invalidRows
  }
}];

